use std::mem;

struct SensorData {
    temperature_celsius: i16,
    humidity_percent: u8,
}

#[derive(Debug)]
struct DeviceRegisters {
    base_address: usize,
}

impl DeviceRegisters {
    fn new(base: usize) -> Self {
        Self { base_address: base }
    }

    fn read_u32(&self, offset: usize) -> u32 {
        unsafe {
            let ptr = self.base_address.wrapping_add(offset);
            std::ptr::read_volatile(ptr as *const u32)
        }
    }

    fn write_u32(&self, offset: usize, value: u32) {
        unsafe {
            let ptr = self.base_address.wrapping_add(offset);
            std::ptr::write_volatile(ptr as *mut u32, value)
        }
    }

    fn get_sensor_reading(&self) -> Result<SensorData, &'static str> {
        let temp_raw = self.read_u32(0x10);
        let hum_raw = self.read_u32(0x14);

        if temp_raw == 0 || hum_raw == 0 {
            return Err("Failed to read sensor data from registers.");
        }

        Ok(SensorData {
            temperature_celsius: (temp_raw & 0xFFFF) as i16,
            humidity_percent: (hum_raw >> 16) as u8,
        })
    }
}

fn main() {
    let peripheral = DeviceRegisters::new(0x4000_0000);
    println!("Simulating sensor read...");
    match peripheral.get_sensor_reading() {
        Ok(data) => println!("Successfully captured data: {:?}", data),
        Err(e) => eprintln!("Error during capture: {}", e),
    }
}

use std::collections::HashMap;

#[derive(Debug)]
struct ProcessContext {
    pid: u32,
    memory_map: HashMap<u64, usize>,
}

impl ProcessContext {
    fn new(pid: u32) -> Self {
        ProcessContext {
            pid,
            memory_map: HashMap::new(),
        }
    }

    fn register_region(&mut self, start_addr: u64, size: usize) {
        self.memory_map.insert(start_addr, size);
    }
}

fn main() {
    let mut context = ProcessContext::new(1024);
    context.register_region(0x80000000, 4096);
    context.register_region(0x90000000, 1024 * 1024);

    println!("Successfully initialized process context for PID: {}", context.pid);
    println!("Memory regions allocated: {:?}", context.memory_map);

    if let Some(&size) = context.memory_map.get(&0x80000000) {
        println!("First region size check: {} bytes", size);
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

#[derive(Debug)]
pub struct FileStateProcessor {
    states: HashMap<String, String>,
}
impl FileStateProcessor {
    pub fn new() -> Self {
        FileStateProcessor { states: HashMap::new() }
    }

    pub fn set_state(&mut self, key: &str, value: &str) {
        self.states.insert(key.to_string(), value.to_string());
    }

    pub fn get_state(&self, key: &str) -> Option<&str> {
        self.states.get(key).map(|s| s.as_str())
    }
}

fn main() {
    let processor = Arc::new(Mutex::new(FileStateProcessor::new()));

    { 
        let mut p = processor.lock().unwrap();
        p.set_state("upload_session", "initialized");
    }

    std::thread::sleep(std::time::Duration::from_millis(50));

    { 
        let mut p = processor.lock().unwrap();
        p.set_state("status_event", "chunk_receiving_12%");
    }

    std::thread::sleep(std::time::Duration::from_millis(50));

    { 
        let mut p = processor.lock().unwrap();
        p.set_state("final_result", "scan_passed_ok");
    }

    if let Some(status) = Arc::new(Mutex::new(FileStateProcessor::new())).lock().unwrap().get_state("final_result") {
        println!("Processing complete. Final status: {}", status);
    }
}

use std::fmt;

struct AnalyzedCommit { id: String, message: String, timestamp: i64 }

impl fmt::Display for AnalyzedCommit {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "[{}] at {} -> {}", &self.id[..7], self.timestamp, &self.message[..20].to_owned())
    }
}

fn main() {
    let commit1 = AnalyzedCommit { id: String::from("a1b2c3d4e5f6"), message: String::from("Initial project setup done"), timestamp: 1678886400 };
    let commit2 = AnalyzedCommit { id: String::from("f6e5d4c3b2a1"), message: String::from("Refactored main logic flow"), timestamp: 1678972800 };

    println!("--- Git Log Snapshot ---n");
    println!("{}n", commit1);
    println!("{}n", commit2);
}

use std::collections::HashMap;

struct VersionedStorage {
    data: HashMap<String, Vec<Vec<u8>>>
}

impl VersionedStorage {
    fn new() -> Self {
        VersionedStorage { data: HashMap::new() }
    }

    fn write_version(&mut self, key: &str, bytes: &[u8]) {
        let entry = self.data.entry(key.to_string()).or_insert_with(Vec::new);
        entry.push(bytes.to_vec());
    }

    fn get_version(&self, key: &str, index: usize) -> Option<&[u8]> {
        self.data.get(key).and_then(|versions| versions.get(index)).map(|v| v.as_slice())
    }
}

fn main() {
    let mut storage = VersionedStorage::new();
    storage.write_version("user_profile", b"initial_data_bytes");
    storage.write_version("user_profile", b"updated_settings_v2");
    storage.write_version("system_config", b"default_state");

    if let Some(data) = storage.get_version("user_profile", 1) {
        println!("Retrieved version 1 data: {}", String::from_utf8_lossy(data));
    }

    if let Some(data) = storage.get_version("system_config", 0) {
        println!("Retrieved system config: {}", String::from_utf8_lossy(data));
    }
}
